import {
  AnchorHTMLAttributes,
  createContext,
  type ReactNode,
  type Context,
} from 'react';
import type { RequireAtLeastOne } from 'type-fest';

import type {
  AriaButtonProps,
  ButtonAria,
} from '../../../buttons/button/types/button-aria.js';
import type { Timeframe } from '../../../core/types/time.js';

/** @internal */
export interface TimeframeSelectorContextProps {
  /** Current value of the timeframe selector */
  details: RequireAtLeastOne<Timeframe> | null;
  /** Element displayed in the input field of the timeframe selector */
  displayValue: ReactNode;
  /** Necessary props for the trigger. */
  triggerProps:
    | (Partial<ButtonAria<AnchorHTMLAttributes<HTMLButtonElement>>> &
        AriaButtonProps)
    | null;
  /** Hint representation for why it is invalid. */
  hint: string;
  readOnly?: boolean;
  /** Whether the trigger should display its error state (combines controlState and FormFieldMessages). */
  showError: boolean;
  /** Whether the trigger is disabled. */
  disabled?: boolean;
}

/**
 * Timeframe selector context, used to access the (input) value and onChange callback in other components.
 * @internal
 */
export const TimeframeSelectorContext: Context<TimeframeSelectorContextProps> =
  createContext<TimeframeSelectorContextProps>({
    details: null,
    displayValue: null,
    triggerProps: null,
    hint: '',
    showError: false,
    disabled: false,
  });
